const Q_COMMERCE_2003=[{"id": "objective>Commerce>2003>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a service – rendering trade association is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nigerian Bar Association</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Association of Nigerian Miners</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cocoa Farmers Association</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Manufacturers Association of Nigerian</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria Bar Association is a non-profit, umbrella professional association of all lawyers admitted to the bar in Nigeria. It engaged in the promotion and protection of human rights, the rule of law and good governance in Nigeria.</div>", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS"}, {"id": "objective>Commerce>2003>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An obstacle to international trade is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">trade imbalance between countries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">availability of local market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quantity and quality of labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost of finance</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">International trade often leads to trade imbalance among nations with the effects that viable countries may not transact business with the weaker ones.</div>", "topic": "TRADE ( 2) : FOREIGN TRADE"}, {"id": "objective>Commerce>2003>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The right of ownership with respect to goods or property is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">right of occupancy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">proxy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">title</div>", "<div style=\"font-family:Cambria;font-size:17px;\">certificate of occupancy</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The right of ownership with respect to goods or property is referred to as 'title'. This is a legal term that means you have legal ownership of something. A title can represent ownership of a real asset such as a car or an intangible property like a trademark.</div>", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT"}, {"id": "objective>Commerce>2003>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main motive of chambers of commerce and trade association is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">assists government in achieving its objectives</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protect the interest of consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">maximized profit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protects and promotes the interest of the members</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The aims and objectives of trade associations are: <br/> - to ensure that members provide good quality services <br/> - to maintain professional ethics of their line of trade <br/> - to defend and advance the interest of members <br/> - to assist members who are in need <br/> - to act as pressure groups in order to influence some government policies <br/>  <br/> Aims and objectives of Chamber of Commerce are: <br/> - to promote commercial activities in a community, country or town <br/> - to liaise with other chambers of commerce in relation to their business  interest <br/> - to influence the policy of the government relating to commercial activities in an area <br/> - to further business interest of the area.</div>", "topic": "TRADE ASSOCIATION : CHAMBER OF COMMERCE"}, {"id": "objective>Commerce>2003>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A pattern that shows the kinds of participants involved in the production,distribution and ultimate use of a product is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">selection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">strategy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">structure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">synergy</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The question is referring to a 'structure' in the context of a market or industry. In this context, a structure refers to the arrangement or organization of the participants involved in the production, distribution, and ultimate use of a product. This includes manufacturers, wholesalers, retailers, and consumers. The structure of a market or industry can have a significant impact on the behavior and performance of businesses within that market or industry.</div>", "topic": "ELEMENT OF MARKETING : MARKETING MIX"}, {"id": "objective>Commerce>2003>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Goods that are manufactured or acquired by the seller after the contract of sale are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">specialty goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">future goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">specific goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">general goods</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the context of a contract of sale, 'future goods' refer to goods that are not yet in existence at the time the contract is made. These goods are manufactured or acquired by the seller after the contract of sale. This is in contrast to 'specific goods', which are identified and agreed upon at the time a contract of sale is made.</div>", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE"}, {"id": "objective>Commerce>2003>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to answer the question that follows  <br/>  Ojo purchased the following items from Sani at the specified prices on  <br/> credit:  <br/>  200 cartons of milk at ₦1,000 per carton; 150 bags of sugar at ₦500 per bag; 50 bags of rice at ₦3,000 per bag. Sani allowed 10% trade discount and 5% cash discount, if payment is made within the agreed period.Ojo paid within the agreed period. <br/>  <br/> What was the amount paid by Ojo?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦382,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦425,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦363,375</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦61,625</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">200 @ 1000 = 200,000 <br/> 150 @ 500 = 75,000 <br/> 50 @ 3000 = 150,000 <br/> Total gross amount = 200,000 + 75,000 + 150,000 <br/>                                               = 425,000 <br/>  <br/> Trade discount = 10% x 425,000 = 42,500 <br/>  <br/> Cash discount = 5% x (425,000 - 42,500) <br/>                                       = 19,125 <br/>  <br/> Total discount = 42,500 + 19,125 <br/>                             = 61,625 <br/>  <br/> Amount paid = 425,000 - 61,625 <br/>                                 = 363,375</div>", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF PAYMENT"}, {"id": "objective>Commerce>2003>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information below to answer the question that follows  <br/>  Ojo purchased the following items from Sani at the specified prices on  <br/> credit:  <br/>  200 cartons of milk at ₦1,000 per carton; 150 bags of sugar at ₦500 per bag; 50 bags of rice at ₦3,000 per bag. Sani allowed 10% trade discount and 5% cash discount, if payment is made within the agreed period.Ojo paid within the agreed period. <br/> How much was the trade discount?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦42,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦27,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦22,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦20,000</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The trade discount is calculated as a percentage of the total cost of the items. In this case, the total cost is ₦425,000 (as calculated in the previous question). So, the trade discount is ₦425,000 * 10% = ₦42,500.</div>", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF PAYMENT"}, {"id": "objective>Commerce>2003>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The basic function of the Nigerian Ports Authority is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ensure that the right caliber of personnel is employed at the ports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coordinates and regulates the activities of shipping line</div>", "<div style=\"font-family:Cambria;font-size:17px;\">facilitates and controls the movement of goods and services into and out of the country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coordinates the activities of all the seaports in the country</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria Port Authority provides facilities at the port to ensure effective and efficient sea transportation. The functions of NPA are: <br/> - Provision of facilities <br/> - Maintenance and improvement of port <br/> - revenue collection <br/> - provision of warehouse <br/> - supervision of loading and off loading of goods.</div>", "topic": "TRADE ( 2) : CUSTOMS, EXCISE, PORTS AUTHORITY ETC."}, {"id": "objective>Commerce>2003>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The concept that refers to the sale, transfer or exchange of goods and services is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">industry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trade</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tariff</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marketing</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The concept that refers to the sale, transfer or exchange of goods and services is 'trade'. Trade involves the transfer or exchange of goods and services from the person or entity that produces them to the person or entity that needs them. It can be done within a country (domestic trade) or between countries (international trade).</div>", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE"}, {"id": "objective>Commerce>2003>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A guarantee given by one person or party to another in which the integrity of the person is assured is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fidelity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">term assurance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">subrogation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">indemnity</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A guarantee given by one person or party to another in which the integrity of the person is assured is 'fidelity'. Fidelity is a concept in business that refers to the assurance that one party will act in good faith and with integrity towards another. It is often used in the context of financial transactions and business relationships.</div>", "topic": "AIDS TO TRADE: INSURANCE : TERMS"}, {"id": "objective>Commerce>2003>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The firm that adapts itself to deliver the desired satisfaction more effectively and efficiently than its competitors is said to be practising</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">price concept</div>", "<div style=\"font-family:Cambria;font-size:17px;\">distribution concept</div>", "<div style=\"font-family:Cambria;font-size:17px;\">product concept</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marketing concept</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Marketing concept starts with a well-defined market, focuses on customer needs, coordinates all the activities that will affect customers, and produce profits by satisfying customers.</div>", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT"}, {"id": "objective>Commerce>2003>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The payment made periodically in respect of an insurance policy entered into is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">premium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">surrender value</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The payment made periodically in respect of an insurance policy is known as a premium. A premium is the amount of money that an individual or business must pay for an insurance policy. The insurance premium is income for the insurance company, once it is earned and regardless of whether the insurance is used.</div>", "topic": "AIDS TO TRADE: INSURANCE : TERMS"}, {"id": "objective>Commerce>2003>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of service rendered by NIPOST is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">electronic mail</div>", "<div style=\"font-family:Cambria;font-size:17px;\">courier</div>", "<div style=\"font-family:Cambria;font-size:17px;\">telephone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mail delivery</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An example of service rendered by NIPOST (Nigerian Postal Service) is mail delivery. NIPOST is responsible for providing postal services in Nigeria. It offers services such as mail delivery, parcel service, EMS, and other related postal services.</div>", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES"}, {"id": "objective>Commerce>2003>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The focal point of marketing is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the competitor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the buyer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">profit-making</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sales</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The focal point of marketing is the buyer. Marketing is a business discipline that focuses on satisfying customers' needs and wants. It involves identifying potential customers, understanding their needs and wants, and developing products or services that meet those needs and wants. Therefore, the buyer is the focal point of all marketing activities.</div>", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT"}, {"id": "objective>Commerce>2003>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The type of marine insurance which cover either damage or loss to the vessel and such as caused by it to other vessels is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hull insurance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">time insurance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">freight insurance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cargo insurance</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hull insurance is a type of marine insurance that covers physical damage to the ship or vessel. It also covers the damages that the insured ship causes to other vessels. This type of insurance is primarily taken out by the owner of the ship in order to avoid any loss to the ship in case of any mishap.</div>", "topic": "AIDS TO TRADE: INSURANCE : TYPES"}, {"id": "objective>Commerce>2003>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The management function that makes the difference in intensity of behavior is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">coordinating</div>", "<div style=\"font-family:Cambria;font-size:17px;\">controlling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">motivation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">planning</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Motivation is the management function that makes the difference in intensity of behavior. It is the process that initiates, guides, and maintains goal-oriented behaviors. It involves the biological, emotional, social, and cognitive forces that activate behavior.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : PRINCIPLE"}, {"id": "objective>Commerce>2003>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the functions of sea ports is the provision of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">berthing and landing facilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">loading and off loading facilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">control room for relaying of radio massage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">warehouses for storage of cargo</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Seaports are facilities that allow ships to dock and unload their cargo. They typically have berths, which are areas where ships can dock, and wharves, which are structures that extend into the water to provide a place for ships to load and unload cargo. <br/>  <br/> Seaports also have other facilities, such as warehouses for storing cargo, cranes for loading and unloading cargo, and roads and railways for transporting cargo to and from the port. <br/>  <br/> However, the most important function of a seaport is to provide berthing and landing facilities. Without these facilities, ships would not be able to dock and unload their cargo.</div>", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION"}, {"id": "objective>Commerce>2003>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process of dividing tasks into jobs and departments and of delegating authority is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">staffing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">leading</div>", "<div style=\"font-family:Cambria;font-size:17px;\">directing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">organizing</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Organizing is a function of management that involves developing an organizational structure and allocating human resources to ensure the accomplishment of objective.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE"}, {"id": "objective>Commerce>2003>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Communication process involves the transmission of a message over a selected channel to the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">receiver</div>", "<div style=\"font-family:Cambria;font-size:17px;\">audience</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sender</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encoder</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Communication process involves the transmission of a message over a selected channel to the receiver. In the communication process, the sender encodes a message and sends it through a channel to the receiver who then decodes the message and gives feedback.</div>", "topic": "AIDS TO TRADE: COMMUNICATION : PROCESS & PROCEDURE"}, {"id": "objective>Commerce>2003>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Stimulation of demand is a kind of communication in marketing which connotes</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">personal selling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sales promotion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">advertising</div>", "<div style=\"font-family:Cambria;font-size:17px;\">merchandising</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sales promotion refers to short-term incentives to encourage the purchase or sale of product or service. These include discounts, coupons, contests, free samples, and other immediate inducements. It is designed to create a sense of urgency and drive immediate demand.</div>", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE"}, {"id": "objective>Commerce>2003>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A functional structure is an organizational structure in which</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">abstract rules are applied</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equity prevails</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a specialist enforces his directives</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is no hierarchy</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A functional structure is an organizational structure in which a specialist enforces his directives. This means that the organization is divided into different departments or teams, and each team is led by a specialist in that particular area. This specialist is responsible for making decisions and enforcing directives within their department.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE"}, {"id": "objective>Commerce>2003>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Entrepreneurship mainly involves</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">risk-taking</div>", "<div style=\"font-family:Cambria;font-size:17px;\">initiating</div>", "<div style=\"font-family:Cambria;font-size:17px;\">skilled manpower</div>", "<div style=\"font-family:Cambria;font-size:17px;\">knowledge</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Entrepreneurship mainly involves risk-taking. While initiating, skilled manpower, and knowledge are all important aspects of entrepreneurship, the defining characteristic is the willingness to take on risk in order to start a new business venture.</div>", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES"}, {"id": "objective>Commerce>2003>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the event of liquidation of a company, the first to be settled are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">debenture holders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">members of the board</div>", "<div style=\"font-family:Cambria;font-size:17px;\">preference share holders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ordinary shareholders</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the event of liquidation of a company, the first to be settled are debenture holders. This is because debenture holders are creditors of the company, and in the event of liquidation, creditors are paid before shareholders. Preference shareholders are paid next, followed by ordinary shareholders.</div>", "topic": "BUSINESS UNIT: MERGER : DISSOLUTION AND LIQUIDATION"}, {"id": "objective>Commerce>2003>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The business organization established mainly for the purpose of carrying out a specific assignment for a specific duration is a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">joint venture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cooperative society</div>", "<div style=\"font-family:Cambria;font-size:17px;\">partnership</div>", "<div style=\"font-family:Cambria;font-size:17px;\">company</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Joint ventures is a business arrangement in which two or more parties  agree to pool their resources for the purpose of accomplishing a specific task.</div>", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES"}, {"id": "objective>Commerce>2003>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these factors of production is relatively fixed in supply?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">entrepreneur</div>", "<div style=\"font-family:Cambria;font-size:17px;\">human resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">natural resources</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In economics, land comprises all naturally occurring resources as well as geographic land. Examples include particular geographical locations, mineral deposits, forests, fish stocks, atmospheric quality etc. supply of these resources is fixed.</div>", "topic": "PRODUCTION : FACTORS OF PRODUCTION"}, {"id": "objective>Commerce>2003>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The location of a business is mostly influenced by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">market outlet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">management decision</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">environment</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The location of a business is mostly influenced by the market outlet. This is because businesses need to be located near their customers for easy access to their products or services. While management decisions, capital, and environment can also influence the location, the primary factor is usually the market outlet.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : BUSINESS RESOURCES"}, {"id": "objective>Commerce>2003>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The evolution of commerce in Nigeria is traceable to the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">period of barter economy as human needs became limitless</div>", "<div style=\"font-family:Cambria;font-size:17px;\">desire by human being to satisfy their needs through the services of their people in the society</div>", "<div style=\"font-family:Cambria;font-size:17px;\">development of human civilizations and the desire to meet their needs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">primitive stage of existence of human beings</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">evolution of commerce in Nigeria is traceable to the period of barter economy as human needs became limitless.</div>", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE"}, {"id": "objective>Commerce>2003>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the requirements necessary for setting up a business is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">registration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">advertisement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">knowledge of the business</div>", "<div style=\"font-family:Cambria;font-size:17px;\">documentation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The knowledge of the business is essential for the effective running and management of any business. Regardless of the formal requirements, understanding the industry, market, and operational aspects is crucial for success. <br/>  <br/> *Note* <br/> Registration is necessary for legal operation in many jurisdications but not universally required for all types of businesses, particularly in informal sectors or small-scale operations.</div>", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES"}, {"id": "objective>Commerce>2003>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The assembling of products into useable forms is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">construction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manufacturing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">formation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">creation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The assembling of products into useable forms is known as manufacturing. Manufacturing involves the conversion of raw materials into finished goods. This process often involves various stages, including the assembly of different components into a final product.</div>", "topic": "PRODUCTION : DIVISION OF LABOUR & SPECIALISATION"}, {"id": "objective>Commerce>2003>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The government's policy of thrust on the business environment is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">promote experts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">attracts investors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">be self-sufficient</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase production</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The government's policy of thrust on the business environment is primarily to attract investors. This is because investors bring in capital, create jobs, and contribute to the overall economic growth of a country. The other options do not directly relate to the government's policy of thrust on the business environment.</div>", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITY : FACTORS"}, {"id": "objective>Commerce>2003>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Social responsibility is the ability of an organization to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tackles the socio-economic problem of its community</div>", "<div style=\"font-family:Cambria;font-size:17px;\">meets the needs of its community</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contribute to sustaining and developing its community</div>", "<div style=\"font-family:Cambria;font-size:17px;\">operates without disrupting the very essence of the environment</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Social responsibility means that businesses, in addition to maximizing shareholder value, should act in a manner that benefits society.</div>", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITY : MEANING AND TYPES"}, {"id": "objective>Commerce>2003>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The act of a person employing another to enter into a contract on his behalf is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">business</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sale of goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bilateral agreement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">agency</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The act of a person employing another to enter into a contract on his behalf is known as agency. In law, an agent is a person who is authorized to act on behalf of another (known as the principal) to create a legal relationship with a third party. The other options do not accurately describe this concept.</div>", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT"}, {"id": "objective>Commerce>2003>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ECOBANK is the initiative of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">some well-meaning Nigerian shareholders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Federal Government of Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">West African State to foster trade</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the Lagos State Government to enhance capital mobilization</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ecobank Transnational Incorporated is a public limited liability company established as  a bank holding company im 1985 under a private sector initiative spearheaded by the Federation of West African Chambers of Commerce and Industry with the support of ECOWAS.</div>", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC."}, {"id": "objective>Commerce>2003>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Privatization is concerned with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">equal ownership between the public and the government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the dilution of ownership among the public</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the individual ownership of companies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government ownership of companies</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Privatization is the process of transferring an enterprise or industry from the public sector to the private sector. </div>", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES"}, {"id": "objective>Commerce>2003>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Electronic computers differ from human beings in that they process data and minimize error in a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">faster and more accurate manner</div>", "<div style=\"font-family:Cambria;font-size:17px;\">more organized manner</div>", "<div style=\"font-family:Cambria;font-size:17px;\">faster but less accurate manner</div>", "<div style=\"font-family:Cambria;font-size:17px;\">slower but more accurate manner</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Electronic computers are designed to process data and perform tasks at a much faster rate than humans, and with a high degree of accuracy. They are not prone to the errors that humans can make, especially when dealing with large amounts of data or complex calculations. Therefore, the correct answer is 'faster and more accurate manner'.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : TYPES OF COMPUTER AND FUNCTIONS"}, {"id": "objective>Commerce>2003>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major benefit derivable from the privatization and commercialization of public enterprises in Nigeria</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase in wages</div>", "<div style=\"font-family:Cambria;font-size:17px;\">employment generation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">information technology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">revenue generation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The advantages of commercialisation and privatisation are: <br/> - reduction in public expenditure <br/> - it promotes efficiency <br/> - generation of more revenue <br/> - emergence of innovations <br/> - better choice by consumers</div>", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVATAGES"}, {"id": "objective>Commerce>2003>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The device which interprets and carries out instructions presented to its by the computer program is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">software</div>", "<div style=\"font-family:Cambria;font-size:17px;\">microprocessor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mouse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hard disk</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A microprocessor is a computer processor that interprets and carries out the instructions of a computer program. It is the 'brain' of the computer where most calculations take place. In contrast, software is a collection of data or computer instructions that tell the computer how to work. A mouse is a pointing device that detects two-dimensional motion relative to a surface. A hard disk is a data storage device used for storing and retrieving digital information.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : ACTIVITIES IN COMPUTER"}, {"id": "objective>Commerce>2003>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The market structure, business conditions and financial systems in Nigeria is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">economic environment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political environment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cultural environment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">technological environment</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Economic environment refers to all the external economic factors that influence buying habits of consumers and businesses and therefore affect the performance of a company.</div>", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITY : FACTORS"}, {"id": "objective>Commerce>2003>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The protection of consumers against exploitation by manufacturers is to ensure</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">that they are varieties of product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">that the right quality of goods and service is sold</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in production capacity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in the level of consumer awareness</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">There are established agencies that execute this duty e.g National Consumer Rights Protection Council.</div>", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION"}, {"id": "objective>Commerce>2003>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most widely used computer language that focuses on solving science-oriented problems is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">FORTRAN</div>", "<div style=\"font-family:Cambria;font-size:17px;\">BASIC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ADA</div>", "<div style=\"font-family:Cambria;font-size:17px;\">COBOL</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">FORTRAN does all science oriented work.It (previously FORTRAN, derived from Formula Translating System) is a general-purpose, imperative programming language that is especially suited to numeric computation and scientific computing.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : TYPES OF COMPUTER AND FUNCTIONS"}, {"id": "objective>Commerce>2003>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Banks are engage in the business of buying and selling of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bills of exchange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">instrument of credit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intangible products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">land</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Banks are engaged in the business of buying and selling of bills of exchange. A bill of exchange is a written order used primarily in international trade that binds one party to pay a fixed sum of money to another party on demand or at a predetermined date. Banks buy these bills at a discount and sell them at a premium, thereby making a profit.</div>", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLEGES"}, {"id": "objective>Commerce>2003>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A source of short-term finance to companies is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">share capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debenture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">retained earnings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">corporate task</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Debenture is a type of loan that is unsecured, meaning that the lender does not have any collateral to seize if the borrower defaults on the loan. Debentures are typically issued by companies to raise short-term financing. <br/>  <br/> Share capital, retained earnings, and corporate tax are all sources of long-term finance.</div>", "topic": "FINANCING BUSINESS : SOURCE OF FINANCE"}, {"id": "objective>Commerce>2003>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The body charged with the responsibility to register shares for subscription on the stock market in Nigeria is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Securities and Exchange Commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigerian Stock Exchange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigerian Deposit Insurance Company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Central Bank of Nigeria</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Security and Exchange Commission (SEC) is the apex regulatory institution of the Nigerian Capital market supervised by the Federal Ministry of Finance and founded in 1979. The Nigerian Stock Exchange (NSE) is privately owned and self regulating, but the NSE is regulated by the SEC.</div>", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS"}, {"id": "objective>Commerce>2003>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An essential factors for evaluating the different sources of funds for a business is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decree establishing the business</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ownership structure of the business concern</div>", "<div style=\"font-family:Cambria;font-size:17px;\">size and the type of business</div>", "<div style=\"font-family:Cambria;font-size:17px;\">burden of cost and repayment</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The burden of cost and repayment refers to the cost of obtaining funds and the obligation to repay them. These are important factors to consider when evaluating funding sources.</div>", "topic": "FINANCING BUSINESS : SOURCE OF FINANCE"}, {"id": "objective>Commerce>2003>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to answer the question that follows  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> What is the owners' equity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦250 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦300 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦420 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦200 000</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Owner equity =  capital + retained earnings <br/>  = ₦200,000  + ₦50,000  <br/>          = ₦250,000</div>", "topic": "FINANCING BUSINESS : TYPES OF CAPITAL"}, {"id": "objective>Commerce>2003>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information below to answer the question that follows  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Find the current ratio</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.53:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.85:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.87:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.50:1</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Current ratio =  current assets ÷ current liability  <br/>  <br/> Current assets = 50000+145000+120000 <br/>                               = 315000 <br/>  <br/> Current liability = 50000+50000+70000 <br/>                                    = 170000 <br/>  <br/> =       315000 ÷ 170000  <br/>                    = 1.85 : 1</div>", "topic": "FINANCING BUSINESS : TYPES OF CAPITAL"}, {"id": "objective>Commerce>2003>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Money can simply be referred to as a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">medium of exchange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">means for the settlements of debts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">durable assets for doing business</div>", "<div style=\"font-family:Cambria;font-size:17px;\">standard of value</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Money is generally accepted, recognized, and centralized medium of exchange in an economy that is used to facilitate transactional trade for goods and services.</div>", "topic": "MONEY : MEANING AND TYPES OF MONEY"}, {"id": "objective>Commerce>2003>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A type of long-term loan granted to companies with fixed interest as well as with redeemable and irredeemable features is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a debenture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a bond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a term loan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an overdraft</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Debenture interest is always fixed. A debenture is a medium- to long-term debt instrument used by large companies to borrow money, at a fixed rate of interest.</div>", "topic": "FINANCING BUSINESS : SOURCE OF FINANCE"}, {"id": "objective>Commerce>2003>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Public debt management is one of the functions of a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">merchant bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">central bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commercial bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">development bank</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Public debt management is the process of establishing and executing a strategy for managing the government's debt in order to raise the required amount of funding at lowest possible cost over the medium to long term, consistent with a prudent degree of risk.  Therefore, Public debt management is one of the functions of a Central bank.</div>", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLEGES"}];
